import React, { useState } from 'react';
import styles from './ShopExamples.module.css';

const TABS = ['Toutes', 'High-Tech', 'Beauté', 'Fitness', 'Maison', 'Mode', 'Bijoux', 'Animaux'];

const SHOPS = [
  {
    id: 1,
    niche: 'High-Tech',
    name: 'TechNova Store',
    logo: 'TN',
    gradient: 'linear-gradient(145deg, #0d1b2a 0%, #1b3a5c 100%)',
    accent: '#3b82f6',
    stats: '⭐ 4.9 · 143 ventes ce mois',
    delivery: 'Livrée en 20h',
  },
  {
    id: 2,
    niche: 'Beauté',
    name: 'GlowUp Beauty',
    logo: 'GU',
    gradient: 'linear-gradient(145deg, #2d0a1e 0%, #4a1235 100%)',
    accent: '#ec4899',
    stats: '⭐ 4.8 · 127 ventes ce mois',
    delivery: 'Livrée en 18h',
  },
  {
    id: 3,
    niche: 'Fitness',
    name: 'IronFit Shop',
    logo: 'IF',
    gradient: 'linear-gradient(145deg, #0a1f0a 0%, #163616 100%)',
    accent: '#22c55e',
    stats: '⭐ 4.7 · 98 ventes ce mois',
    delivery: 'Livrée en 22h',
  },
  {
    id: 4,
    niche: 'Maison',
    name: 'Maison Lumière',
    logo: 'ML',
    gradient: 'linear-gradient(145deg, #1f1600 0%, #3a2d00 100%)',
    accent: '#f59e0b',
    stats: '⭐ 4.8 · 112 ventes ce mois',
    delivery: 'Livrée en 16h',
  },
  {
    id: 5,
    niche: 'Mode',
    name: 'UrbanStyle Co.',
    logo: 'US',
    gradient: 'linear-gradient(145deg, #1a0a2d 0%, #2d1450 100%)',
    accent: '#a855f7',
    stats: '⭐ 4.9 · 189 ventes ce mois',
    delivery: 'Livrée en 19h',
  },
  {
    id: 6,
    niche: 'Bijoux',
    name: 'Éclat Doré',
    logo: 'ED',
    gradient: 'linear-gradient(145deg, #1f1500 0%, #3d2c00 100%)',
    accent: '#c9a84c',
    stats: '⭐ 4.8 · 76 ventes ce mois',
    delivery: 'Livrée en 23h',
  },
  {
    id: 7,
    niche: 'Animaux',
    name: 'PetLove Store',
    logo: 'PL',
    gradient: 'linear-gradient(145deg, #001a2d 0%, #002d1a 100%)',
    accent: '#06b6d4',
    stats: '⭐ 4.7 · 91 ventes ce mois',
    delivery: 'Livrée en 21h',
  },
  {
    id: 8,
    niche: 'High-Tech',
    name: 'PixelGear Pro',
    logo: 'PG',
    gradient: 'linear-gradient(145deg, #05091f 0%, #0d1a3d 100%)',
    accent: '#6366f1',
    stats: '⭐ 4.9 · 201 ventes ce mois',
    delivery: 'Livrée en 17h',
  },
];

export default function ShopExamples() {
  const [activeTab, setActiveTab] = useState('Toutes');
  const [fading, setFading] = useState(false);

  const handleTab = (tab) => {
    if (tab === activeTab) return;
    setFading(true);
    setTimeout(() => {
      setActiveTab(tab);
      setFading(false);
    }, 140);
  };

  const scrollToOffer = () => {
    document.querySelector('#offer')?.scrollIntoView({ behavior: 'smooth' });
  };

  const visible = activeTab === 'Toutes'
    ? SHOPS
    : SHOPS.filter(s => s.niche === activeTab);

  return (
    <section className={styles.section}>
      <div className={styles.label}>NOS BOUTIQUES</div>
      <h2 className={styles.title}>Des boutiques prêtes à vendre dès le premier jour</h2>
      <p className={styles.sub}>
        Chaque boutique est livrée avec un design pro, des produits gagnants et un thème adapté à ta niche
      </p>

      {/* Filter tabs */}
      <div className={styles.tabs}>
        {TABS.map(tab => (
          <button
            key={tab}
            className={`${styles.tab} ${activeTab === tab ? styles.tabActive : ''}`}
            onClick={() => handleTab(tab)}
          >
            {tab}
          </button>
        ))}
      </div>

      {/* Cards grid */}
      <div className={`${styles.grid} ${fading ? styles.gridFading : ''}`}>
        {visible.map(shop => (
          <div key={shop.id} className={styles.card}>
            {/* Fake screenshot mockup */}
            <div className={styles.mockup} style={{ background: shop.gradient }}>
              {/* Fake nav */}
              <div className={styles.mockNav} style={{ borderBottomColor: `${shop.accent}30` }}>
                <span className={styles.mockLogo} style={{ color: shop.accent }}>
                  {shop.logo}
                </span>
                <div className={styles.mockNavLinks}>
                  <span className={styles.mockNavLink} />
                  <span className={styles.mockNavLink} />
                  <span className={styles.mockNavLink} />
                </div>
                <div className={styles.mockCartBtn} style={{ background: shop.accent }}>
                  Acheter
                </div>
              </div>

              {/* Fake content */}
              <div className={styles.mockBody}>
                <div
                  className={styles.mockBanner}
                  style={{ background: `${shop.accent}18`, borderColor: `${shop.accent}28` }}
                />
                <div className={styles.mockProds}>
                  {[0, 1, 2].map(i => (
                    <div key={i} className={styles.mockProd}>
                      <div
                        className={styles.mockProdImg}
                        style={{ background: `${shop.accent}22` }}
                      />
                      <div className={styles.mockProdInfo}>
                        <div className={styles.mockProdLine} />
                        <div
                          className={styles.mockProdPrice}
                          style={{ background: shop.accent }}
                        />
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>

            {/* Card info */}
            <div className={styles.cardBody}>
              <span className={styles.nicheBadge} style={{ color: shop.accent, borderColor: `${shop.accent}40`, background: `${shop.accent}12` }}>
                {shop.niche}
              </span>
              <h3 className={styles.shopName}>{shop.name}</h3>
              <p className={styles.shopStats}>{shop.stats}</p>
              <p className={styles.shopDelivery}>🚀 {shop.delivery} · Niche : {shop.niche}</p>
            </div>
          </div>
        ))}
      </div>

      {/* CTA */}
      <div className={styles.ctaWrap}>
        <button className={styles.ctaBtn} onClick={scrollToOffer}>
          Je veux ma boutique à 37€ →
        </button>
      </div>
    </section>
  );
}
